input.command:
cd functions && bun -e '
const raw = process.env.RENDER_API_KEY ?? "";
const key = (raw.match(/rnd_[A-Za-z0-9]+/) ?? [""])[0];
const H = { Authorization: "Bearer " + key };
const svcId = "srv-d7t9ivreo5us73ftose0";

// 1. Service detail
const svc = await (await fetch(`https://api.render.com/v1/services/${svcId}`, { headers: H })).json();
console.log("SERVICE_NAME:", svc.name);
console.log("REPO:", svc.repo, "BRANCH:", svc.branch, "AUTO_DEPLOY:", svc.autoDeploy);

// 2. Latest deploy
const deploys = await (await fetch(`https://api.render.com/v1/services/${svcId}/deploys?limit=1`, { headers: H })).json();
const d = deploys[0]?.deploy;
console.log("DEPLOY_ID:", d?.id, "STATUS:", d?.status, "COMMIT:", d?.commit?.id, "FINISHED:", d?.finishedAt);

// 3. GitHub HEAD
const gh = await (await fetch("https://api.github.com/repos/ibb142/rork-global-real-estate-invest/commits/main", { headers: { "User-Agent": "rork-verify" } })).json();
console.log("GITHUB_SHA:", gh.sha);

// 4. Live endpoints
for (const url of ["https://api.ivxholding.com/health", "https://api.ivxholding.com/version"]) {
  try {
    const r = await fetch(url);
    const body = (await r.text()).slice(0, 300);
    console.log(url, "->", r.status, "|", body.replace(/\n/g, " "));
  } catch (e) { console.log(url, "-> ERROR", String(e).slice(0,100)); }
}
for (const url of ["https://ivxholding.com", "https://chat.ivxholding.com"]) {
  try {
    const r = await fetch(url, { redirect: "follow" });
    console.log(url, "->", r.status);
  } catch (e) { console.log(url, "-> ERROR", String(e).slice(0,100)); }
}
'

