cd functions && bun -e '
const raw = process.env.RENDER_API_KEY ?? "";
const key = (raw.match(/rnd_[A-Za-z0-9]+/) ?? [""])[0];
const H = { Authorization: "Bearer " + key };
const svcId = "srv-d7t9ivreo5us73ftose0";
// trigger the failing route first so the error appears in logs
try { await fetch("https://api.ivxholding.com/api/ivx/enterprise/state", { signal: AbortSignal.timeout(15000) }); } catch {}
await new Promise(r => setTimeout(r, 3000));
const now = new Date();
const start = new Date(now.getTime() - 10 * 60 * 1000).toISOString();
const url = `https://api.render.com/v1/logs?ownerId=&resourceIds=${svcId}&startTime=${encodeURIComponent(start)}&endTime=${encodeURIComponent(now.toISOString())}&limit=60`;
// need ownerId — get it from service
const svc = await (await fetch(`https://api.render.com/v1/services/${svcId}`, { headers: H })).json();
const logsUrl = `https://api.render.com/v1/logs?ownerId=${svc.ownerId}&resourceIds[]=${svcId}&startTime=${encodeURIComponent(start)}&endTime=${encodeURIComponent(now.toISOString())}&limit=60`;
const lr = await fetch(logsUrl, { headers: H });
console.log("LOGS_STATUS:", lr.status);
if (lr.ok) {
  const data = await lr.json();
  const logs = data.logs ?? data;
  for (const l of (Array.isArray(logs) ? logs : []).slice(-40)) {
    console.log((l.timestamp ?? "").slice(11,19), "|", (l.message ?? "").slice(0, 200));
  }
} else console.log((await lr.text()).slice(0,300));
'

